$inputPayload = $env:InputPayload | ConvertFrom-Json;

$StackName = $inputPayload.StackName;
$VPCId = $inputPayload.VPCId;
$Subnet1Id = $inputPayload.Subnet1Id;
$Subnet2Id = $inputPayload.Subnet2Id;
$PlatformType = $inputPayload.PlatformType;
$AMIId = $inputPayload.AMIId;
$EIPAllocationId = $inputPayload.EIPAllocationId;
$ELBDNSName = $inputPayload.ELBDNSName;
$InputELBType = $inputPayload.InputELBType;
$DeploymentBucketName = $inputPayload.DeploymentBucketName;
$PortalLicenseFile = $inputPayload.PortalLicenseFile;
$ServerLicenseFile = $inputPayload.ServerLicenseFile;
$SSLCertificateFile = $inputPayload.SSLCertificateFile;
$SiteadminPasswordValue = $inputPayload.SiteadminPasswordValue;
$ArcGISUserPasswordValue = $inputPayload.ArcGISUserPasswordValue;
$SSLCertificatePasswordValue = $inputPayload.SSLCertificatePasswordValue;
$WaitCondition = $inputPayload.WaitCondition;
$ActionName = $inputPayload.ActionName;
$LogGroupName = $inputPayload.LogGroupName;
$global:RegionId = $inputPayload.RegionId;

$guid = New-Guid;
$LogStreamName = "$guid/$ActionName/stderr"
$global:LogSequenceToken = ""
[bool] $global:ErrorFound = $false

Install-Module AWS.Tools.CloudFormation -Force
Install-Module AWS.Tools.CloudWatchLogs -Force
Install-Module AWS.Tools.EC2 -Force
Install-Module AWS.Tools.ElasticLoadBalancing -Force
Install-Module AWS.Tools.ElasticLoadBalancingV2 -Force
Install-Module AWS.Tools.S3 -Force
Install-Module AWS.Tools.SecretsManager -Force

Import-Module AWS.Tools.CloudFormation
Import-Module AWS.Tools.CloudWatchLogs
Import-Module AWS.Tools.EC2
Import-Module AWS.Tools.ElasticLoadBalancing
Import-Module AWS.Tools.ElasticLoadBalancingV2
Import-Module AWS.Tools.S3
Import-Module AWS.Tools.SecretsManager
function WriteErrorLog($errormessage) {
  Write-Error $errormessage | format-list -force
  if ([string]::IsNullOrEmpty($global:LogSequenceToken)) {
    $splat = @{
      LogGroupName = $LogGroupName
      LogStreamName =  $LogStreamName
    }
    New-CWLLogStream @splat -Region $global:RegionId

    $logEntry = New-Object Amazon.CloudWatchLogs.Model.InputLogEvent
    $logEntry.Message = $errormessage
    $logEntry.Timestamp = (Get-Date).ToUniversalTime()

    $splat = @{
      LogEvent      = $logEntry
      LogGroupName  = $LogGroupName
      LogStreamName = $LogStreamName
    }
    $global:LogSequenceToken = Write-CWLLogEvent @splat -Region $global:RegionId
  } else {
    $logEntry =  New-Object Amazon.CloudWatchLogs.Model.InputLogEvent
    $logEntry.Message = $errormessage
    $logEntry.Timestamp = (Get-Date).ToUniversalTime()

    $splat = @{
      LogEvent      = $logEntry
      LogGroupName  = $LogGroupName
      LogStreamName = $LogStreamName
      SequenceToken = $global:LogSequenceToken
    }
    $global:LogSequenceToken = Write-CWLLogEvent @splat -Region $global:RegionId
  }
  $global:ErrorFound = $true
  return $global:LogSequenceToken
}

#check for subnets
if (-not [string]::IsNullOrEmpty($VPCId)) {
  try {
    if ($Subnet1Id -eq $Subnet2Id) { 
      $global:LogSequenceToken = WriteErrorLog("Subnet1 Id $Subnet1Id and Subnet2 Id $Subnet2Id cannot be same.")
    }
    if (-not [string]::IsNullOrEmpty($Subnet1Id)) {
      $Subnet1 = (Get-EC2Subnet -SubnetId $Subnet1Id -Region $global:RegionId | Where-Object {$_.VpcId -eq $VPCId}).SubnetId
      if ([string]::IsNullOrEmpty($Subnet1)) {
        $global:LogSequenceToken = WriteErrorLog("Subnet1 Id $Subnet1Id does not belong to VPC Id $VPCId.")
      }
    }
    if (-not [string]::IsNullOrEmpty($Subnet2Id)) {
      $Subnet2 = (Get-EC2Subnet -SubnetId $Subnet2Id -Region $global:RegionId | Where-Object {$_.VpcId -eq $VPCId}).SubnetId
      if ([string]::IsNullOrEmpty($Subnet2)) {
        $global:LogSequenceToken = WriteErrorLog("Subnet2 Id $Subnet2Id does not belong to VPC Id $VPCId.")
      }
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog($_.Exception.Message)
  }
}

#check for AMI Id
if (-not [string]::IsNullOrEmpty($AMIId)) {
  try {
    $PlatformDetails = (Get-EC2Image -ImageId $AMIId -Region $global:RegionId).PlatformDetails
    if (-not $PlatformDetails.ToLower().Contains($PlatformType.ToLower())) {
      $global:LogSequenceToken = WriteErrorLog("For specified AMI Id $AMIId platform type is $PlatformDetails. It does not belong to selected platform type $PlatformType. Choose correct platform type or enter correct AMI Id.")
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog($AMIId + " : " + $_.Exception.Message)
  }
}

#check for EIP
if (-not [string]::IsNullOrEmpty($EIPAllocationId)) {
  try {
    $AllocationId = (Get-EC2Address -AllocationId $EIPAllocationId -Region $global:RegionId).AllocationId
    if ([string]::IsNullOrEmpty($AllocationId)) {
      $global:LogSequenceToken = WriteErrorLog("EIP allocation id $EIPAllocationId does not exists. Enter correct EIP allocation id.")
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog($EIPAllocationId + " : " + $_.Exception.Message)
  }
}

#check for ELB DNS Name
if (-not [string]::IsNullOrEmpty($ELBDNSName)) {
  try {
    $ELBExists = $false
    $ELBType = (Get-ELB2LoadBalancer -Region $global:RegionId | Where-Object {$_.DNSName -eq $ELBDNSName}).Type.Value
    if (-not [string]::IsNullOrEmpty($ELBType)) {
      if ($ELBType -eq $InputELBType) {
        $ELBExists = $true
      } else {
        $global:LogSequenceToken = WriteErrorLog("ELB type for ELBDNSName $ELBDNSName is incorrect. Allowed ELB Type is $InputELBType.")
      }
    }
    if (-not $ELBExists) {
    $CLBName = (Get-ELBLoadBalancer -Region $global:RegionId | Where-Object {$_.DNSName -eq $ELBDNSName}).LoadBalancerName
      if (-not [string]::IsNullOrEmpty($CLBName)) {
        $ELBExists = $true
      }
    }
    if (-not $ELBExists) {
      $global:LogSequenceToken = WriteErrorLog("ELB DNS Name $ELBDNSName does not found. Make sure ELB with specified ELB DNS name does exists.")
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog($ELBDNSName + " : " + $_.Exception.Message)
  }
}

#check for deployment bucket
$DeploymentBucketRegion = ''
if (-not [string]::IsNullOrEmpty($DeploymentBucketName)) {
  try {
    $DeploymentBucketRegion = (Get-S3BucketLocation -BucketName $DeploymentBucketName -Region $global:RegionId).Value
    if ([string]::IsNullOrEmpty($DeploymentBucketRegion)) {
      $DeploymentBucketRegion = 'us-east-1'
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog($DeploymentBucketName + " : " + $_.Exception.Message)
  }
}

if (-not [string]::IsNullOrEmpty($DeploymentBucketRegion)) {
  if (-not [string]::IsNullOrEmpty($PortalLicenseFile)) {
    try {
      if(-not (Get-S3Object -BucketName $DeploymentBucketName -Region $DeploymentBucketRegion | Where-Object {$_.Key -eq $PortalLicenseFile})){
        $global:LogSequenceToken = WriteErrorLog("Portal license file $PortalLicenseFile does not exists in deployment bucket $DeploymentBucketName.")
      }
    } catch {
      Write-Error $_.Exception.Message | format-list -force
      $global:LogSequenceToken = WriteErrorLog($PortalLicenseFile + " : " + $_.Exception.Message)
    }
  }
  if (-not [string]::IsNullOrEmpty($ServerLicenseFile)) {
    try {
      if(-not (Get-S3Object -BucketName $DeploymentBucketName -Region $DeploymentBucketRegion | Where-Object {$_.Key -eq $ServerLicenseFile})){
        $global:LogSequenceToken = WriteErrorLog("Server license file $ServerLicenseFile does not exists in deployment bucket $DeploymentBucketName.")
      }
    } catch {
      Write-Error $_.Exception.Message | format-list -force
      $global:LogSequenceToken = WriteErrorLog($ServerLicenseFile + " : " + $_.Exception.Message)
    }
  }
  if (-not [string]::IsNullOrEmpty($SSLCertificateFile)) {
    try {
      if(-not (Get-S3Object -BucketName $DeploymentBucketName -Region $DeploymentBucketRegion | Where-Object {$_.Key -eq $SSLCertificateFile})){
        $global:LogSequenceToken = WriteErrorLog("SSL Certificate file $SSLCertificateFile does not exists in deployment bucket $DeploymentBucketName.")
      }
    } catch {
      Write-Error $_.Exception.Message | format-list -force
      $global:LogSequenceToken = WriteErrorLog($SSLCertificateFile + " : " + $_.Exception.Message)
    }
  }
}

if (-not [string]::IsNullOrEmpty($SiteadminPasswordValue)) {
  try {
    if ($SiteadminPasswordValue -match '^arn:(aws[a-zA-Z-]*)?:secretsmanager:[a-z]{2}((-gov)|(-iso(b?)))?-[a-z]+-\d{1}:\d{12}:secret:[a-zA-Z0-9-/_+=.@]*$') {
      $SiteadminPassword = (Get-SECSecretValue -SecretId $SiteadminPasswordValue -Region $global:RegionId).SecretString
      if (([string]::IsNullOrEmpty($SiteadminPassword))) {
        $global:LogSequenceToken = WriteErrorLog("Siteadmin user password secret id does not found or not accessible.")
      } else {
        if (-not ($SiteadminPassword -match '^[a-zA-Z0-9_.@]{8,}$')) {
          $global:LogSequenceToken = WriteErrorLog("Siteadmin user password mentioned in the specified secret does not match password policies. Refer to ArcGIS Enterprise CloudFomration document for password policies.")
        }
      }
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog("SiteAdmin Password : " + $_.Exception.Message)
  }
}

if (([string]::IsNullOrEmpty($ArcGISUserPasswordValue)) -and ($PlatformType -eq 'Windows')) {
  $global:LogSequenceToken = WriteErrorLog("'arcgisUserPassword' parameter value cannot be empty if platform type is 'Windows'.")
}

if (-not [string]::IsNullOrEmpty($ArcGISUserPasswordValue)) {
  try {
    if ($ArcGISUserPasswordValue -match '^arn:(aws[a-zA-Z-]*)?:secretsmanager:[a-z]{2}((-gov)|(-iso(b?)))?-[a-z]+-\d{1}:\d{12}:secret:[a-zA-Z0-9-/_+=.@]*$') {
      $ArcGISUserPassword = (Get-SECSecretValue -SecretId $ArcGISUserPasswordValue -Region $global:RegionId).SecretString
      if (([string]::IsNullOrEmpty($ArcGISUserPassword))) {
        $global:LogSequenceToken = WriteErrorLog("'arcgis' user password secret id does not found or not accessible.")
      } else {
        if (-not ($ArcGISUserPassword -match "(?!.*arcgis)(?!.*Arc)(?!.*GIS)(?!.*user)(?!.*account)^((?=.*[a-z])(?=.*[A-Z])(?=.*\d)|(?=.*[a-z])(?=.*[A-Z])(?=.*[^A-Za-z0-9])|(?=.*[a-z])(?=.*\d)(?=.*[^A-Za-z0-9])|(?=.*[A-Z])(?=.*\d)(?=.*[^A-Za-z0-9]))([A-Za-z\d@#$%&�*\-_+=\[\]{}|:\',?~();!]|\.(?!@)){8,}$")) {
          $global:LogSequenceToken = WriteErrorLog("'arcgis' user password mentioned in the specified secret does not match password policies. Refer to ArcGIS Enterprise CloudFomration document for password policies.")
        }
      }
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog("'arcgis' user Password : " + $_.Exception.Message)
  }
}

if (-not [string]::IsNullOrEmpty($SSLCertificatePasswordValue)) {
  try {
    if ($SSLCertificatePasswordValue -match '^arn:(aws[a-zA-Z-]*)?:secretsmanager:[a-z]{2}((-gov)|(-iso(b?)))?-[a-z]+-\d{1}:\d{12}:secret:[a-zA-Z0-9-/_+=.@]*$') {
      $SSLCertificatePassword = (Get-SECSecretValue -SecretId $SSLCertificatePasswordValue -Region $global:RegionId).SecretString
      if (([string]::IsNullOrEmpty($SSLCertificatePassword))) {
        $global:LogSequenceToken = WriteErrorLog("SSL Certificate password secret id does not found or not accessible.")
      } else {
        if (-not ($SSLCertificatePassword -match '[^\"]{1,128}')) {
          $global:LogSequenceToken = WriteErrorLog("SSL Certificate password mentioned in the specified secret does not match password policies. Refer to ArcGIS Enterprise CloudFomration document for password policies.")
        }
      }
    }
  } catch {
    Write-Error $_.Exception.Message | format-list -force
    $global:LogSequenceToken = WriteErrorLog("SSL Certificate Password : " + $_.Exception.Message)
  }
}

if ($global:ErrorFound) {
  $Status = "FAILURE"
  $UniqueId = "FAILURE"
} else {
  $Status = "SUCCESS"
  $UniqueId = "SUCCESS"
}

if (-not ([string]::IsNullOrEmpty($WaitCondition)))
{
  $stackstatus=((Get-CFNStack -StackName $StackName -Region $global:RegionId).StackStatus).Value
  if ($stackstatus -eq "CREATE_IN_PROGRESS") 
  {
    try {
      Send-CFNResourceSignal -StackName $StackName -LogicalResourceId $WaitCondition -Status $Status -UniqueId $UniqueId -Region $global:RegionId
    }
    catch
    {
      Write-Error $_.Exception | format-list -force
      $global:LogSequenceToken = WriteErrorLog("Failed to send signal back to CloudFormation stack. Refer to deployment logs $LogGroupName for error details." + $_.Exception)
      Write-Error "Failed to send signal back to CloudFormation stack." -ErrorAction Stop
    }
  }
  if ($Status -eq "FAILURE") {
    $global:LogSequenceToken = WriteErrorLog("Failed to validate input parameter for $StackName CloudFormation stack.")
    Write-Error "Failed to validate input parameter for $StackName CloudFormation stack. Refer to deployment logs $LogGroupName for error details." -ErrorAction Stop
  }
}

