import cfnresponse
import boto3
import logging
import json

def delete_server_config_store(event, context):
    print('Received request:\n%s' % json.dumps(event, indent=4))
    properties = event['ResourceProperties']
    if event['RequestType'] == 'Delete':
        response = {}
        namespace = properties['Namespace']
        try:
            dynamodb = boto3.resource('dynamodb')
            s3 = boto3.resource('s3')

            logger = logging.getLogger()
            logger.setLevel(logging.INFO)

            config_stores_table = dynamodb.Table('ArcGISConfigStores')
            config_store_item = config_stores_table.get_item(Key = {'Namespace': namespace})
            db_table_name=""
            s3_bucket_name=""

            try:
                db_table_name = config_store_item['Item']['DBTableName']
            except Exception as e:
                logger.error('Failed to retrieve DynamoDB table. {}'.format(e))

            try:
                s3_bucket_name = config_store_item['Item']['S3BucketName']
            except Exception as e:
                logger.error('Failed to retrieve S3 bucket. {}'.format(e))

            if db_table_name:
                try:
                    logger.info('DynamoDB table name is {}.'.format(db_table_name))
                    dynamodb.Table(db_table_name).delete()
                    logger.info('DynamoDB table {} deleted.'.format(db_table_name))
                except Exception as e:
                    logger.error('Failed to delete DynamoDB table {}. {}'.format(db_table_name, e))
                try:
                    logger.info('DynamoDB table name namespace is {}.'.format(namespace))
                    config_stores_table.delete_item(Key = {'Namespace': namespace})
                    logger.info('DynamoDB table namespace {} deleted.'.format(namespace))
                except Exception as e:
                    logger.error('Failed to delete DynamoDB table namepsace {} item. {}'.format(namespace, e))

            if s3_bucket_name:
                try:
                    logger.info('ArcGIS Server content S3 bucket name is {}.'.format(s3_bucket_name))
                    s3_bucket = s3.Bucket(s3_bucket_name)
                    for key in s3_bucket.objects.all():
                        key.delete()
                    s3_bucket.delete()
                    logger.info('ArcGIS Server content S3 bucket {} deleted.'.format(s3_bucket_name))
                except Exception as e:
                    logger.error('Failed to delete ArcGIS Server content S3 bucket {}. {}'.format(s3_bucket_name, e))

            response['Message'] = 'ArcGIS Server config store with namespace {} deleted.'.format(namespace)
        except Exception as e:
            response['ErrorMessage'] = 'Failed to delete ArcGIS Server config store with namespace {}. {}'.format(namespace, e)
            cfnresponse.send(event, context, cfnresponse.SUCCESS, response)
        else:
            cfnresponse.send(event, context, cfnresponse.SUCCESS, response)
    elif event['RequestType'] in ['Create', 'Update']:
        cfnresponse.send(event, context, cfnresponse.SUCCESS, {})

